mapper.select:
SELECT o.opening_id, o.project_id, p.project_name, o.lot_id, l.lot_code, l.lot_name, o.status, o.opening_time, o.opening_place, o.host_employee_id, o.recorder_employee_id, o.summary, o.abnormal_flag, o.abnormal_reason, o.version, o.create_time, o.update_time FROM t_bid_opening o INNER JOIN t_bid_project p ON p.project_id = o.project_id INNER JOIN t_bid_lot l ON l.lot_id = o.lot_id
o.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0 AND l.deleted_flag = 0
AND ( p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR o.opening_place LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND o.project_id = #{queryForm.projectId}
AND o.lot_id = #{queryForm.lotId}
AND o.status = #{queryForm.status}
ORDER BY o.opening_time DESC, o.opening_id DESC
